# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3
import json

app = Flask(__name__)

# Initialize Web3 connection (adjust RPC URL as needed)
w3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    try:
        data = request.get_json()
        
        # Extract required fields
        message = data.get('message')
        signature = data.get('signature')
        address = data.get('address')
        
        if not all([message, signature, address]):
            return jsonify({'error': 'Missing required fields'}), 400
        
        # Recover address from signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Check if recovered address matches provided address
        if recovered_address.lower() == address.lower():
            return jsonify({
                'valid': True,
                'address': recovered_address
            })
        else:
            return jsonify({
                'valid': False,
                'error': 'Address mismatch'
            }), 401
            
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)